            <style type="text/css">

                .menu-o-proekte {

                }

                /* .hoverIGATION */
                .menu-o-proekte,
                .menu-o-proekte:after,
                .menu-o-proekte:before {
                  transition: all .5s;
                }
                .menu-o-proekte:hover {
                  color: #FFFFFF;  
                }


                /* stroke */
                .menu-o-proekte.stroke,
                .menu-o-proekte.fill {
                  position: relative;
                }
                .menu-o-proekte.stroke:after,
                .menu-o-proekte.fill:after {
                  position: absolute;
                  bottom: 0;
                  left: 0;
                  right: 0;
                  margin: auto;
                  width: 0%;
                  content: '.';
                  color: transparent;
                  background: #FF196C;
                  height: 1px;
                }

                .menu-o-proekte.stroke:hover:after {
                  width: 100%;
                }

                .menu-o-proekte.fill {
                  transition: all 2s;
                }

