            <style type="text/css">

                .menu-dokumenti {

                }

                /* .hoverIGATION */
                .menu-dokumenti,
                .menu-dokumenti:after,
                .menu-dokumenti:before {
                  transition: all .5s;
                }
                .menu-dokumenti:hover {
                  color: #FFFFFF;  
                }


                /* stroke */
                .menu-dokumenti.stroke,
                .menu-dokumenti.fill {
                  position: relative;
                }
                .menu-dokumenti.stroke:after,
                .menu-dokumenti.fill:after {
                  position: absolute;
                  bottom: 0;
                  left: 0;
                  right: 0;
                  margin: auto;
                  width: 0%;
                  content: '.';
                  color: transparent;
                  background: #D4145A;
                  height: 1px;
                }

                .menu-dokumenti.stroke:hover:after {
                  width: 100%;
                }

                .menu-dokumenti.fill {
                  transition: all 2s;
                }

                .menu-dokumenti.fill:after {
                  text-align: left;
                  content: '.';
                  margin: 0;
                  opacity: 0;
                }
                .menu-dokumenti.fill:hover {
                  color: #FFFFFF;
                  z-index: 1;
                }
                .menu-dokumenti.fill:hover:after {
                  z-index: -10;
                  animation: fill 1s forwards;
                  -webkit-animation: fill 1s forwards;
                  -moz-animation: fill 1s forwards;
                  opacity: 1;
                }

                /* Circle */
                .menu-dokumenti.circle {
                  position: relative;
                  overflow: hidden;
                  z-index: 1;
                }
                .menu-dokumenti.circle:after {
                  display: block;
                  position: absolute;
                  margin: 0;
                  top: 0;
                  bottom: 0;
                  left: 0;
                  right: 0;
                  content: '.';
                  color: transparent;
                  width: 1px;
                  height: 1px;
                  border-radius: 50%;
                  background: transparent;
                }
                .menu-dokumenti.circle:hover:after {
                  -webkit-animation: circle 1.5s ease-in forwards;
                }

                /* SHIFT */
                .menu-dokumenti.shift {
                  position:relative;
                  z-index: 1;
                }
                .menu-dokumenti.shift:hover {
                  color: #FFFFFF;
                }
                .menu-dokumenti.shift:after {
                  display: block;
                  position: absolute;
                  top: 0;
                  left: 0;
                  bottom: 0;
                  right: 0;
                  margin: auto;
                  width: 100%;
                  height: 1px;
                  content: '.';
                  color: transparent;
                  background: #D4145A;
                  visibility: none;
                  opacity: 0;
                  z-index: -1;
                  border-radius: 12px;
                }
                .menu-dokumenti.shift:hover:after {
                  opacity: 1;
                  visibility: visible;
                  height: 100%;
                }



                /* Keyframes */
                @-webkit-keyframes fill {
                  0% {
                    width: 0%;
                    height: 1px;
                  }
                  50% {
                    width: 100%;
                    height: 1px;
                  }
                  100% {
                    width: 100%;
                    height: 100%;
                    background: #D4145A;
                  }
                }

